package com.example.sharereceiver

import android.content.Intent
import android.net.Uri
import android.os.Build
import android.os.Bundle
import android.util.Log
import android.widget.ImageView
import android.widget.LinearLayout
import android.widget.ScrollView
import android.widget.TextView
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity

class ShareReceiverActivity : AppCompatActivity() {

    companion object {
        private const val TAG = "ShareReceiverActivity"
    }

    private lateinit var statusTextView: TextView
    private lateinit var contentContainer: LinearLayout

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        val scrollView = ScrollView(this).apply {
            layoutParams = LinearLayout.LayoutParams(
                LinearLayout.LayoutParams.MATCH_PARENT,
                LinearLayout.LayoutParams.MATCH_PARENT
            )
            setPadding(32, 32, 32, 32)
        }

        contentContainer = LinearLayout(this).apply {
            orientation = LinearLayout.VERTICAL
            layoutParams = LinearLayout.LayoutParams(
                LinearLayout.LayoutParams.MATCH_PARENT,
                LinearLayout.LayoutParams.WRAP_CONTENT
            )
        }

        statusTextView = TextView(this).apply {
            textSize = 18f
            setPadding(0, 0, 0, 24)
        }

        contentContainer.addView(statusTextView)
        scrollView.addView(contentContainer)
        setContentView(scrollView)

        handleIncomingIntent(intent)
    }

    override fun onNewIntent(intent: Intent) {
        super.onNewIntent(intent)
        handleIncomingIntent(intent)
    }

    private fun handleIncomingIntent(intent: Intent) {
        when {
            intent.action == Intent.ACTION_SEND && intent.type != null -> {
                when {
                    intent.type == "text/plain" -> handleSharedText(intent)
                    intent.type?.startsWith("image/") == true -> handleSharedImage(intent)
                    else -> {
                        showStatus("Unsupported content type: ${intent.type}")
                    }
                }
            }
            intent.action == Intent.ACTION_SEND_MULTIPLE && intent.type?.startsWith("image/") == true -> {
                handleSharedMultipleImages(intent)
            }
            else -> {
                showStatus("No shared content detected.")
            }
        }
    }

    private fun handleSharedText(intent: Intent) {
        val sharedText = intent.getStringExtra(Intent.EXTRA_TEXT)
        val sharedSubject = intent.getStringExtra(Intent.EXTRA_SUBJECT)

        if (sharedText != null) {
            Log.d(TAG, "Received shared text: $sharedText")

            val url = extractUrl(sharedText)

            if (url != null) {
                showStatus("Received shared URL")
                processSharedUrl(url, sharedSubject)
            } else {
                showStatus("Received shared text")
                processSharedText(sharedText, sharedSubject)
            }
        } else {
            showStatus("Received empty text share")
            Toast.makeText(this, "No text content received", Toast.LENGTH_SHORT).show()
        }
    }

    private fun handleSharedImage(intent: Intent) {
        val imageUri: Uri? = if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {
            intent.getParcelableExtra(Intent.EXTRA_STREAM, Uri::class.java)
        } else {
            @Suppress("DEPRECATION")
            intent.getParcelableExtra(Intent.EXTRA_STREAM)
        }

        if (imageUri != null) {
            Log.d(TAG, "Received shared image: $imageUri")
            showStatus("Received shared image")
            processSharedImage(imageUri)
        } else {
            showStatus("Received empty image share")
            Toast.makeText(this, "No image content received", Toast.LENGTH_SHORT).show()
        }
    }

    private fun handleSharedMultipleImages(intent: Intent) {
        val imageUris: ArrayList<Uri>? = if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {
            intent.getParcelableArrayListExtra(Intent.EXTRA_STREAM, Uri::class.java)
        } else {
            @Suppress("DEPRECATION")
            intent.getParcelableArrayListExtra(Intent.EXTRA_STREAM)
        }

        if (!imageUris.isNullOrEmpty()) {
            Log.d(TAG, "Received ${imageUris.size} shared images")
            showStatus("Received ${imageUris.size} shared images")
            imageUris.forEach { uri ->
                processSharedImage(uri)
            }
        } else {
            showStatus("Received empty multiple image share")
            Toast.makeText(this, "No images received", Toast.LENGTH_SHORT).show()
        }
    }

    private fun extractUrl(text: String): String? {
        val urlPattern = Regex(
            "(https?://[\\w\\-._~:/?#\\[\\]@!$&'()*+,;=%]+)",
            RegexOption.IGNORE_CASE
        )
        val matchResult = urlPattern.find(text)
        return matchResult?.value
    }

    private fun processSharedUrl(url: String, subject: String?) {
        val urlLabel = TextView(this).apply {
            text = "URL: $url"
            textSize = 16f
            setPadding(0, 8, 0, 8)
            setTextIsSelectable(true)
        }
        contentContainer.addView(urlLabel)

        if (!subject.isNullOrBlank()) {
            val subjectLabel = TextView(this).apply {
                text = "Subject: $subject"
                textSize = 14f
                setPadding(0, 4, 0, 8)
                setTextIsSelectable(true)
            }
            contentContainer.addView(subjectLabel)
        }

        // Process the URL - save to database, open in WebView, etc.
        saveSharedContent(type = "url", content = url, metadata = subject)

        Toast.makeText(this, "URL received: $url", Toast.LENGTH_LONG).show()
    }

    private fun processSharedText(text: String, subject: String?) {
        val textLabel = TextView(this).apply {
            this.text = "Text: $text"
            textSize = 16f
            setPadding(0, 8, 0, 8)
            setTextIsSelectable(true)
        }
        contentContainer.addView(textLabel)

        if (!subject.isNullOrBlank()) {
            val subjectLabel = TextView(this).apply {
                this.text = "Subject: $subject"
                textSize = 14f
                setPadding(0, 4, 0, 8)
                setTextIsSelectable(true)
            }
            contentContainer.addView(subjectLabel)
        }

        // Process the text - save, analyze, etc.
        saveSharedContent(type = "text", content = text, metadata = subject)

        Toast.makeText(this, "Text received", Toast.LENGTH_SHORT).show()
    }

    private fun processSharedImage(imageUri: Uri) {
        try {
            // Request read permission for the URI
            contentResolver.takePersistableUriPermission(
                imageUri,
                Intent.FLAG_GRANT_READ_URI_PERMISSION
            )
        } catch (e: SecurityException) {
            Log.w(TAG, "Could not take persistable URI permission: ${e.message}")
        }

        val imageView = ImageView(this).apply {
            layoutParams = LinearLayout.LayoutParams(
                LinearLayout.LayoutParams.MATCH_PARENT,
                600
            ).apply {
                setMargins(0, 16, 0, 16)
            }
            scaleType = ImageView.ScaleType.FIT_CENTER
            adjustViewBounds = true
        }

        try {
            imageView.setImageURI(imageUri)
            contentContainer.addView(imageView)

            val uriLabel = TextView(this).apply {
                text = "Image URI: $imageUri"
                textSize = 12f
                setPadding(0, 4, 0, 16)
                setTextIsSelectable(true)
            }
            contentContainer.addView(uriLabel)

            // Get image details
            val mimeType = contentResolver.getType(imageUri)
            val detailsLabel = TextView(this).apply {
                text = "MIME Type: $mimeType"
                textSize = 12f
                setPadding(0, 0, 0, 16)
            }
            contentContainer.addView(detailsLabel)

            // Process the image - copy to app storage, upload, etc.
            saveSharedContent(type = "image", content = imageUri.toString(), metadata = mimeType)

            Toast.makeText(this, "Image received", Toast.LENGTH_SHORT).show()
        } catch (e: Exception) {
            Log.e(TAG, "Error loading shared image", e)
            val errorLabel = TextView(this).apply {
                text = "Error loading image: ${e.message}"
                textSize = 14f
                setPadding(0, 8, 0, 8)
            }
            contentContainer.addView(errorLabel)
            Toast.makeText(this, "Error loading image", Toast.LENGTH_SHORT).show()
        }
    }

    private fun saveSharedContent(type: String, content: String, metadata: String?) {
        // Placeholder for saving shared content
        // In a real app, you would save to a database, shared preferences,
        // upload to a server, etc.
        Log.d(TAG, "Saving shared content - Type: $type, Content: $content, Metadata: $metadata")

        val prefs = getSharedPreferences("shared_content", MODE_PRIVATE)
        val timestamp = System.currentTimeMillis()
        prefs.edit().apply {
            putString("last_share_type", type)
            putString("last_share_content", content)
            putString("last_share_metadata", metadata)
            putLong("last_share_timestamp", timestamp)
            apply()
        }
    }

    private fun showStatus(message: String) {
        statusTextView.text = message
        Log.d(TAG, "Status: $message")
    }
